// ===== CLIENTE =====
const clientName = $node["Dados principais"].json["Client_ID"] || 'Cliente';

// ===== INPUT =====
const allItems = $input.all();

let metaAds = [];
let googleAds = [];

// ===== SEPARAÇÃO INTELIGENTE =====
for (const item of allItems) {
  if (item.json.data && Array.isArray(item.json.data)) {
    item.json.data.forEach(entry => {

      // META → tem ad_name
      if (entry.ad_name) {
        metaAds.push(entry);
      }

      // GOOGLE → não tem ad_name, mas tem campaign
      else if (entry.campaign || entry.campaign_name) {
        googleAds.push(entry);
      }

    });
  }
}

// ===== META NORMALIZAÇÃO =====
const parsedMeta = metaAds.map(ad => {
  const impressions = Number(ad.impressions) || 0;
  const clicks = Number(ad.clicks) || 0;
  const spend = Number(ad.spend) || 0;

  let conversions = 0;

  if (Array.isArray(ad.actions)) {
    const msg = ad.actions.find(a =>
      a.action_type === "onsite_conversion.messaging_conversation_started_7d"
    );

    if (msg) conversions = Number(msg.value);

    if (!conversions) {
      const alt = ad.actions.find(a =>
        a.action_type === "onsite_conversion.total_messaging_connection"
      );
      conversions = alt ? Number(alt.value) : 0;
    }
  }

  return {
    source: 'Meta',
    campaign: ad.campaign_name,
    ad_name: ad.ad_name,
    impressions,
    clicks,
    spend,
    conversions,
    ctr: impressions > 0 ? clicks / impressions : 0,
    cpc: clicks > 0 ? spend / clicks : 0,
    thumbnail_url: ad.thumbnail_url || ''
  };
});

// ===== GOOGLE NORMALIZAÇÃO =====
const parsedGoogle = googleAds.map(g => {
  const impressions = Number(g.impressions) || 0;
  const clicks = Number(g.clicks) || 0;
  const spend = Number(g.spend) || 0;
  const conversions = Number(g.conversions) || 0;

  return {
    source: 'Google',
    campaign: g.campaign || g.campaign_name,
    ad_name: g.campaign || g.campaign_name,
    impressions,
    clicks,
    spend,
    conversions,
    ctr: impressions > 0 ? clicks / impressions : 0,
    cpc: clicks > 0 ? spend / clicks : 0
  };
});

// ===== JUNTAR =====
const allAds = [...parsedMeta, ...parsedGoogle];

// ===== RESUMO =====
let total = {
  spend: 0,
  clicks: 0,
  impressions: 0,
  conversions: 0
};

allAds.forEach(ad => {
  total.spend += ad.spend;
  total.clicks += ad.clicks;
  total.impressions += ad.impressions;
  total.conversions += ad.conversions;
});

const summary = {
  spend: total.spend,
  clicks: total.clicks,
  impressions: total.impressions,
  conversions: total.conversions,
  ctr: total.impressions > 0 ? total.clicks / total.impressions : 0,
  cpc: total.clicks > 0 ? total.spend / total.clicks : 0,
  cpa: total.conversions > 0 ? total.spend / total.conversions : 0
};

// ===== CAMPANHAS =====
const campaignsMap = {};

allAds.forEach(ad => {
  if (!campaignsMap[ad.campaign]) {
    campaignsMap[ad.campaign] = {
      name: ad.campaign,
      source: ad.source,
      spend: 0,
      clicks: 0,
      impressions: 0,
      conversions: 0
    };
  }

  const c = campaignsMap[ad.campaign];

  c.spend += ad.spend;
  c.clicks += ad.clicks;
  c.impressions += ad.impressions;
  c.conversions += ad.conversions;
});

const campaigns = Object.values(campaignsMap).map(c => ({
  ...c,
  ctr: c.impressions > 0 ? c.clicks / c.impressions : 0,
  cpc: c.clicks > 0 ? c.spend / c.clicks : 0,
  cpa: c.conversions > 0 ? c.spend / c.conversions : 0
}));

// ===== TOP CRIATIVOS (SÓ META) =====
const topAds = parsedMeta
  .sort((a, b) => b.spend - a.spend)
  .slice(0, 3);

// ===== OUTPUT =====
return [{
  json: {
    clientName,
    summary,
    campaigns,
    topAds
  }
}];
